from autogen import ConversableAgent, GroupChat

def domain_router(last_speaker: ConversableAgent, groupchat: GroupChat) -> ConversableAgent:
    """Route based on keywords in the last message."""
    agents = {a.name: a for a in groupchat.agents}
    last_msg = groupchat.messages[-1].get("content", "") if groupchat.messages else ""

    if "code" in last_msg.lower() or "implement" in last_msg.lower():
        return agents.get("coder")
    elif "review" in last_msg.lower() or "check" in last_msg.lower():
        return agents.get("critic")
    elif "research" in last_msg.lower() or "find" in last_msg.lower():
        return agents.get("researcher")
    else:
        # Default: let user_proxy decide (it will respond or pass)
        return agents.get("user_proxy")

group_chat = GroupChat(
    agents=[user_proxy, researcher, coder, critic],
    messages=[],
    max_round=12,
    speaker_selection_method=domain_router,
)
# No LLM cost for speaker selection — pure keyword routing
manager = GroupChatManager(groupchat=group_chat, llm_config=False)
